// Normaliza o payload do webhook da Evolution (event: messages.upsert)
// para o formato esperado por /api/n8n/mensagem. Descarta o que não for
// uma mensagem de TEXTO de um CLIENTE (ignora fromMe, grupos e mídia).

const raw = $input.first().json;
const body = raw.body ?? raw; // o Webhook coloca o corpo em .body
const data = body.data ?? {};
const key = data.key ?? {};

// 1. Só o evento de mensagem recebida
if (body.event && body.event !== 'messages.upsert') return [];

// 2. Ignora mensagens enviadas pela própria loja (eco do bot)
if (key.fromMe) return [];

// 3. Extrai o texto (conversation ou extendedTextMessage)
const texto = (
  data.message?.conversation ||
  data.message?.extendedTextMessage?.text ||
  ''
).trim();
if (!texto) return []; // sem texto (áudio/imagem/etc.) → ignora

// 4. Ignora grupos
const remoteJid = key.remoteJid || '';
if (remoteJid.endsWith('@g.us')) return [];

// 5. Telefones (só dígitos) e ids
const telefoneCliente = remoteJid.split('@')[0].split(':')[0];
const numeroLoja = String(body.sender || '').split('@')[0].split(':')[0];
const mensagemId = key.id;
const nomeCliente = data.pushName || '';

if (!telefoneCliente || !numeroLoja || !mensagemId) return [];

return [{ json: { numeroLoja, telefoneCliente, texto, mensagemId, nomeCliente } }];
